arguments.command:
cat > /tmp/drawio/salary_flow.dot << 'DOT_EOF'
digraph SalaryFlow {
    // Graph settings
    rankdir=TB;
    node [fontname="Microsoft YaHei", fontsize=12, shape=box, style=filled, fillcolor="#e8f4fd", penwidth=2];
    edge [fontname="Microsoft YaHei", fontsize=10, color="#555"];

    // Start/End nodes (ellipse)
    start [label="开始", shape=ellipse, fillcolor="#d4edda", style=filled];
    end_node [label="结束", shape=ellipse, fillcolor="#f8d7da", style=filled];

    // Process nodes
    emp_fill [label="员工填写\n薪资申报表"];
    submit [label="提交申请"];
    finance_pay [label="财务发放\n薪资", fillcolor="#fff3cd"];

    // Decision nodes (diamond)
    manager_check [label="直属上级审核通过？", shape=diamond, fillcolor="#e2e3f1"];
    hr_check [label="HR部门复核通过？", shape=diamond, fillcolor="#e2e3f1"];
    finance_check [label="财务部审批通过？", shape=diamond, fillcolor="#e2e3f1"];

    // Reject nodes (rounded)
    modify1 [label="修改后重新提交", style=rounded, fillcolor="#ffeaa7"];
    reject_hr [label="退回HR修改", style=rounded, fillcolor="#ffeaa7"];
    reject_fin [label="退回修改", style=rounded, fillcolor="#ffeaa7"];

    // Edges
    start -> emp_fill;
    emp_fill -> submit;
    submit -> manager_check;

    // Manager check branches
    manager_check -> emp_fill [label="否", dir=back];
    manager_check -> hr_check [label="是"];

    // HR check branches  
    hr_check -> reject_hr [label="否"];
    reject_hr -> emp_fill [dir=back, label="退回修改", constraint=false];
    hr_check -> finance_check [label="是"];

    // Finance check branches
    finance_check -> reject_fin [label="否"];
    reject_fin -> emp_fill [dir=back, constraint=false];
    finance_check -> finance_pay [label="是"];

    finance_pay -> end_node;
}
DOT_EOF
dot -Tpng /tmp/drawio/salary_flow.dot -o /tmp/drawio/salary_flow.png 2>&1 && ls -la /tmp/drawio/salary_flow.png && echo "SUCCESS" || echo "FAILED"

